const checkboxes = document.getElementsByName('status-filter');
		const url = new URL(window.location);
		const status = url.searchParams.get('status');
		if (status) {
			const activeStatuses = status.split(',');
			for (const checkbox of checkboxes) {
				checkbox.checked = activeStatuses.includes(checkbox.value);
			}
		}
		document.getElementById('status-filters').addEventListener('change', (event) => {
			const url = new URL(window.location);
			url.searchParams.set('status', Array.from(checkboxes).filter(cb => cb.checked).map(cb => cb.value));
			window.history.replaceState({}, '', url);
		});
